import { useState, useRef } from 'react'
import { useParams } from 'react-router-dom'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const containerRef = useRef(null)

  const [selectedColor, setSelectedColor] = useState(
    product.colors[0]
  )

  const [selectedSize, setSelectedSize] = useState('M')

  const [uploadedLogo, setUploadedLogo] = useState(null)

  const [logoSize, setLogoSize] = useState(220)

  const [isDragging, setIsDragging] = useState(false)

  const [view, setView] = useState('front')

  const [frontPosition, setFrontPosition] = useState({
    x: 50,
    y: 42
  })

  const [backPosition, setBackPosition] = useState({
    x: 50,
    y: 42
  })

  const [sleevePosition, setSleevePosition] = useState({
    x: 72,
    y: 33
  })

  const currentPosition =
    view === 'front'
      ? frontPosition
      : view === 'back'
      ? backPosition
      : sleevePosition

  const setCurrentPosition =
    view === 'front'
      ? setFrontPosition
      : view === 'back'
      ? setBackPosition
      : setSleevePosition

  const handleUpload = (e) => {

    const file = e.target.files[0]

    if (file) {
      setUploadedLogo(URL.createObjectURL(file))
    }
  }

  const handleMouseMove = (e) => {

    if (!isDragging) return

    const rect =
      containerRef.current.getBoundingClientRect()

    const x =
      ((e.clientX - rect.left) / rect.width) * 100

    const y =
      ((e.clientY - rect.top) / rect.height) * 100

    setCurrentPosition({
      x,
      y
    })
  }

  const handleMouseUp = () => {
    setIsDragging(false)
  }

  const setPreset = (type) => {

    if (type === 'front') {

      setFrontPosition({
        x: 50,
        y: 42
      })

      setLogoSize(220)
    }

    if (type === 'left-chest') {

      setFrontPosition({
        x: 38,
        y: 32
      })

      setLogoSize(120)
    }

    if (type === 'oversized') {

      setFrontPosition({
        x: 50,
        y: 45
      })

      setLogoSize(420)
    }

    if (type === 'back') {

      setBackPosition({
        x: 50,
        y: 42
      })

      setLogoSize(320)

      setView('back')
    }

    if (type === 'sleeve') {

      setSleevePosition({
        x: 72,
        y: 33
      })

      setLogoSize(90)

      setView('sleeve')
    }
  }

  return (

    <div
      className="min-h-screen bg-black text-white px-6 py-20"
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
    >

      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-16">


        <div
          ref={containerRef}
          className="bg-[#111] border border-[#222] rounded-[40px] p-10 flex items-center justify-center relative overflow-hidden min-h-[850px]"
        >

          <img
            src={selectedColor.image}
            alt="product"
            className="w-full max-w-[700px] relative z-10"
          />


          {uploadedLogo && (

            <img
              src={uploadedLogo}
              alt="logo"
              onMouseDown={() => setIsDragging(true)}
              className="absolute z-20 opacity-90 mix-blend-multiply select-none"
              style={{
                width: `${logoSize}px`,
                top: `${currentPosition.y}%`,
                left: `${currentPosition.x}%`,
                transform: 'translate(-50%, -50%)',
                cursor: isDragging ? 'grabbing' : 'grab'
              }}
              draggable={false}
            />

          )}


          <img
            src="/mockups/wrinkle-overlay.png"
            alt="wrinkle"
            className="absolute inset-0 w-full h-full object-cover z-30 opacity-40 mix-blend-overlay pointer-events-none"
          />


          <img
            src="/mockups/texture-overlay.png"
            alt="texture"
            className="absolute inset-0 w-full h-full object-cover z-40 opacity-20 mix-blend-soft-light pointer-events-none"
          />

        </div>


        <div>

          <p className="text-yellow-500 tracking-[0.4em] uppercase text-xs mb-6">
            Inspired By God Print Division
          </p>


          <h1 className="text-7xl font-black leading-none mb-6">
            {product.name}
          </h1>


          <p className="text-3xl text-yellow-500 mb-14">
            Starting at ${product.price}
          </p>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Print Side
            </h2>


            <div className="flex flex-wrap gap-4">

              <button
                onClick={() => setView('front')}
                className={`px-8 py-4 rounded-2xl font-black ${
                  view === 'front'
                    ? 'bg-yellow-500 text-black'
                    : 'border border-[#333]'
                }`}
              >
                Front
              </button>


              <button
                onClick={() => setView('back')}
                className={`px-8 py-4 rounded-2xl font-black ${
                  view === 'back'
                    ? 'bg-yellow-500 text-black'
                    : 'border border-[#333]'
                }`}
              >
                Back
              </button>


              <button
                onClick={() => setView('sleeve')}
                className={`px-8 py-4 rounded-2xl font-black ${
                  view === 'sleeve'
                    ? 'bg-yellow-500 text-black'
                    : 'border border-[#333]'
                }`}
              >
                Sleeve
              </button>

            </div>

          </div>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Quick Placement
            </h2>


            <div className="flex flex-wrap gap-4">

              <button
                onClick={() => setPreset('front')}
                className="px-6 py-4 bg-yellow-500 text-black rounded-2xl font-black"
              >
                Front
              </button>

              <button
                onClick={() => setPreset('left-chest')}
                className="px-6 py-4 border border-[#333] rounded-2xl"
              >
                Left Chest
              </button>

              <button
                onClick={() => setPreset('oversized')}
                className="px-6 py-4 border border-[#333] rounded-2xl"
              >
                Oversized
              </button>

              <button
                onClick={() => setPreset('back')}
                className="px-6 py-4 border border-[#333] rounded-2xl"
              >
                Back Print
              </button>

              <button
                onClick={() => setPreset('sleeve')}
                className="px-6 py-4 border border-[#333] rounded-2xl"
              >
                Sleeve
              </button>

            </div>

          </div>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Select Color
            </h2>


            <div className="flex gap-4 flex-wrap">

              {product.colors.map((color) => (

                <button
                  key={color.name}
                  onClick={() => setSelectedColor(color)}
                  className={`w-16 h-16 rounded-full border-4 transition ${
                    selectedColor.name === color.name
                      ? 'border-yellow-500 scale-110'
                      : 'border-white'
                  }`}
                  style={{
                    backgroundColor: color.hex
                  }}
                />

              ))}

            </div>

          </div>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Select Size
            </h2>


            <div className="flex flex-wrap gap-4">

              {['S','M','L','XL','2XL','3XL'].map((size) => (

                <button
                  key={size}
                  onClick={() => setSelectedSize(size)}
                  className={`px-8 py-4 rounded-2xl border transition text-lg font-bold ${
                    selectedSize === size
                      ? 'bg-yellow-500 text-black border-yellow-500'
                      : 'border-[#333] text-white'
                  }`}
                >
                  {size}
                </button>

              ))}

            </div>

          </div>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Upload Logo
            </h2>


            <input
              type="file"
              accept="image/png,image/jpeg"
              onChange={handleUpload}
              className="w-full bg-[#111] border border-[#222] rounded-2xl p-5"
            />

          </div>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Resize Logo
            </h2>


            <input
              type="range"
              min="80"
              max="500"
              value={logoSize}
              onChange={(e) =>
                setLogoSize(e.target.value)
              }
              className="w-full"
            />

          </div>


          <button className="w-full bg-yellow-500 text-black py-6 rounded-3xl text-xl font-black hover:scale-[1.02] transition duration-300">

            REQUEST QUOTE

          </button>

        </div>

      </div>

    </div>

  )
}
